 1	import * as React from 'react';
 2	import { GraphToolbarActions } from 'actions/GraphToolbarActions';
 3	import { bindActionCreators } from 'redux';
 4	import { KialiDispatch } from 'types/Redux';
 5	import { connect } from 'react-redux';
 6	import { Tooltip, Button, ButtonVariant } from '@patternfly/react-core';
 7	import { KialiIcon } from 'config/KialiIcon';
 8	import { kialiStyle } from 'styles/StyleUtils';
 9	
10	type ReduxProps = {
11	  resetSettings: () => void;
12	};
13	
14	type GraphResetProps = ReduxProps & {};
15	
16	const resetStyle = kialiStyle({
17	  marginLeft: '0.5rem',
18	  alignSelf: 'center'
19	});
20	
21	const GraphResetComponent: React.FC<GraphResetProps> = (props: GraphResetProps) => {
22	  const onReset = (): void => {
23	    props.resetSettings();
24	  };
25	
26	  return (
27	    <Tooltip key="factory_reset_settings" position="bottom" content="Reset to factory settings">
28	      <Button
29	        id="graph-factory-reset"
30	        className={resetStyle}
31	        variant={ButtonVariant.link}
32	        onClick={() => onReset()}
33	        isInline
34	      >
35	        <KialiIcon.ResetSettings />
36	        <span style={{ marginLeft: '5px' }}>Reset</span>
37	      </Button>
38	    </Tooltip>
39	  );
40	};
41	
42	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxProps => {
43	  return {
44	    resetSettings: bindActionCreators(GraphToolbarActions.resetSettings, dispatch)
45	  };
46	};
47	
48	export const GraphReset = connect(null, mapDispatchToProps)(GraphResetComponent);

